  if (flows   > 0) parts.push(`${flows} flow${flows === 1 ? '' : 's'}`);
  if (notes   > 0) parts.push(`${notes} note${notes === 1 ? '' : 's'}`);
  if (skipped > 0) parts.push(`${skipped} skipped`);

