     1→import { describe, test, expect } from 'bun:test';
     2→import rehypeImageMetadata from './rehype-image-metadata';
     3→import type { Root, Element } from 'hast';
     4→
     5→/** Build a minimal HAST tree containing a single <img> node. */
     6→function makeTree(src: string): Root {
     7→  return {
     8→    type: 'root',
     9→    children: [
    10→      {
    11→        type: 'element',
    12→        tagName: 'img',
    13→        properties: { src },
    14→        children: [],
    15→      } satisfies Element,
    16→    ],
    17→  };
    18→}
    19→
    20→function imgSrc(tree: Root): unknown {
    21→  return (tree.children[0] as Element).properties.src;
    22→}
    23→
    24→describe('rehype-image-metadata', () => {
    25→  describe('relative paths (./)', () => {
    26→    test('resolves to posts public path when slug is posts/{slug}', () => {
    27→      const tree = makeTree('./images/photo.png');
    28→      rehypeImageMetadata({ slug: 'posts/my-post' })(tree);
    29→      expect(imgSrc(tree)).toBe('/posts/my-post/images/photo.png');
    30→    });
    31→
    32→    test('resolves to books public path when slug is books/{slug}', () => {
    33→      const tree = makeTree('./images/cover.jpg');
    34→      rehypeImageMetadata({ slug: 'books/my-book' })(tree);
    35→      expect(imgSrc(tree)).toBe('/books/my-book/images/cover.jpg');
    36→    });
    37→
    38→    test('resolves to flows public path when slug is flows/{year}/{month}/{day}', () => {
    39→      const tree = makeTree('./images/snap.jpg');
    40→      rehypeImageMetadata({ slug: 'flows/2026/01/15' })(tree);
    41→      expect(imgSrc(tree)).toBe('/flows/2026/01/15/images/snap.jpg');
    42→    });
    43→
    44→    test('resolves to notes public path when slug is notes/{slug}', () => {
    45→      const tree = makeTree('./images/diagram.svg');
    46→      rehypeImageMetadata({ slug: 'notes/my-note' })(tree);
    47→      expect(imgSrc(tree)).toBe('/notes/my-note/images/diagram.svg');
    48→    });
    49→
    50→    test('does not modify src when no slug is provided', () => {
    51→      const tree = makeTree('./images/photo.png');
    52→      rehypeImageMetadata({})(tree);
    53→      expect(imgSrc(tree)).toBe('./images/photo.png');
