  const noteContent = [
    '---',
    `title: "${escapedTitle}"`,
    `date: "${date}"`,
    `tags: ${tagsLiteral(tags)}`,
    `aliases: ${tagsLiteral(aliases)}`,
    '---',
    '',
    body,
    '',
  ].join('\n');

  if (dryRun) {
    console.log(`    [note] "${title}" → content/notes/${slug}.md`);
    if (tags.length > 0) console.log(`           tags: ${tags.join(', ')}`);
    return true;
  }

  if (existing) {
    console.log(`    ⚠  "${slug}": note already exists — skipped`);
    return false;
  }

